import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { searchRentals, fetchStates, fetchPropertyTypes } from '../utils/api';
import { LoadingState, ErrorState, EmptyState } from '../components/LoadingState';
import Pagination from '../components/Pagination';

const formatPrice = (p) => (p != null ? `$${Number(p).toLocaleString('en-AU')}/wk` : '—');

const SearchPage = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  const [states, setStates] = useState([]);
  const [propertyTypes, setPropertyTypes] = useState([]);

  // 1. Unified Filter State
  const [filters, setFilters] = useState({
    state: searchParams.get('state') || '',
    suburb: searchParams.get('suburb') || '',
    postcode: searchParams.get('postcode') || '',
    propertyType: searchParams.get('propertyType') || '', 
    minPrice: searchParams.get('minPrice') || '',
    maxPrice: searchParams.get('maxPrice') || '',
    bedrooms: searchParams.get('bedrooms') || '',
    bathrooms: searchParams.get('bathrooms') || '',
    parkingSpaces: searchParams.get('parkingSpaces') || '',
  });

  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(Number(searchParams.get('page')) || 1);

  const debounceRef = useRef(null);

  useEffect(() => {
    fetchStates().then(setStates).catch(() => {});
    fetchPropertyTypes().then(setPropertyTypes).catch(() => {});
  }, []);

  // 2. Optimized Search Logic
  const doSearch = useCallback(async (currentFilters, currentPage) => {
    setLoading(true);
    setError(null);

    try {
      // Map frontend camelCase to API snake_case
      const apiParams = {
        page: currentPage,
        state: currentFilters.state,
        suburb: currentFilters.suburb,
        postcode: currentFilters.postcode,
        property_type: currentFilters.propertyType,
        min_price: currentFilters.minPrice,
        max_price: currentFilters.maxPrice,
        bedrooms: currentFilters.bedrooms,
        bathrooms: currentFilters.bathrooms,
        parking_spaces: currentFilters.parkingSpaces,
      };

      // Clean up params: Convert numbers and remove empty strings
      const finalParams = {};
      Object.keys(apiParams).forEach((key) => {
        const val = apiParams[key];
        if (val !== '' && val !== null) {
          // If it looks like a number, send it as a number type
          finalParams[key] = !isNaN(val) && val !== '' ? Number(val) : val;
        }
      });

      const response = await searchRentals(finalParams);
      setResults(response);
    } catch (err) {
      setError(err.message || 'Search failed.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      doSearch(filters, page);
      
      const urlParams = {};
      Object.entries(filters).forEach(([k, v]) => { if (v) urlParams[k] = v; });
      if (page > 1) urlParams.page = page;
      setSearchParams(urlParams, { replace: true });
    }, 400);
    return () => clearTimeout(debounceRef.current);
  }, [filters, page, doSearch, setSearchParams]);

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
    setPage(1);
  };

  const resetFilters = () => {
    setFilters({
      state: '', suburb: '', postcode: '', propertyType: '',
      minPrice: '', maxPrice: '', bedrooms: '', bathrooms: '',
      parkingSpaces: '',
    });
    setPage(1);
  };

  const rentals = results?.data || [];
  const totalCount = results?.pagination?.total || 0;
  const totalPages = results?.pagination?.lastPage || 1;

  return (
    <div className="search-page">
      <aside className="search-page__sidebar">
        <div className="filter-panel">
          <div className="filter-panel__header">
            <h2>Filters</h2>
            <button className="filter-reset-btn" onClick={resetFilters}>Reset</button>
          </div>

          {/* State Filter */}
          <div className="filter-group">
            <label className="filter-label">State</label>
            <select
              className="filter-select"
              value={filters.state}
              onChange={(e) => handleFilterChange('state', e.target.value)}
            >
              <option value="">All States</option>
              {states.map((s) => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div className="filter-group">
            <label className="filter-label">Property Type</label>
            <select
              className="filter-select"
              value={filters.propertyType}
              onChange={(e) => handleFilterChange('propertyType', e.target.value)}
            >
              <option value="">All Types</option>
              {propertyTypes.map((t) => (
                <option key={t} value={t}>{t.charAt(0).toUpperCase() + t.slice(1)}</option>
              ))}
            </select>
          </div>

          <div className="filter-group">
            <label className="filter-label">Rent Range</label>
            <div className="filter-row">
              <input
                className="filter-input"
                type="number"
                placeholder="Min"
                value={filters.minPrice}
                onChange={(e) => handleFilterChange('minPrice', e.target.value)}
              />
              <input
                className="filter-input"
                type="number"
                placeholder="Max"
                value={filters.maxPrice}
                onChange={(e) => handleFilterChange('maxPrice', e.target.value)}
              />
            </div>
          </div>

          <div className="filter-group">
            <label className="filter-label">Rooms & Parking</label>
            <div className="filter-row">
              <input
                className="filter-input"
                type="number"
                placeholder="Beds"
                value={filters.bedrooms}
                onChange={(e) => handleFilterChange('bedrooms', e.target.value)}
              />
              <input
                className="filter-input"
                type="number"
                placeholder="Baths"
                value={filters.bathrooms}
                onChange={(e) => handleFilterChange('bathrooms', e.target.value)}
              />
            </div>
            <input
              className="filter-input"
              type="number"
              placeholder="Parking Spaces"
              style={{marginTop: '8px'}}
              value={filters.parkingSpaces}
              onChange={(e) => handleFilterChange('parkingSpaces', e.target.value)}
            />
          </div>
        </div>
      </aside>

      <main className="search-page__results">
        <header className="results-header">
          <h1>{loading ? 'Searching...' : `${totalCount.toLocaleString()} Listings`}</h1>
        </header>

        {loading && <LoadingState />}
        {error && <ErrorState message={error} />}

        {!loading && rentals.length > 0 && (
          <div className="results-table-wrapper">
            <table className="results-table">
              <thead>
                <tr>
                  <th>Address</th>
                  <th>State</th>
                  <th>Type</th>
                  <th>Bed</th>
                  <th>Bath</th>
                  <th>Park</th>
                  <th>Price</th>
                </tr>
              </thead>
              <tbody>
                {rentals.map((r) => (
                  <tr key={r.id} className="results-table__row" onClick={() => navigate(`/rental/${r.id}`)}>
                    <td className="results-table__address">
                      <strong>{r.title}</strong><br />
                      <small>{r.suburb} {r.postcode}</small>
                    </td>
                    <td>{r.state}</td>
                    <td style={{textTransform: 'capitalize'}}>{r.propertyType}</td>
                    <td>{r.bedrooms}</td>
                    <td>{r.bathrooms}</td>
                    <td>{r.parkingSpaces}</td>
                    <td className="results-table__price">{formatPrice(r.rent)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {!loading && !error && rentals.length > 0 && (
          <div className="pagination-container">
            <Pagination
              page={page}
              totalPages={totalPages}
              onPageChange={setPage}
            />
          </div>
        )}

        {!loading && !error && rentals.length === 0 && <EmptyState />}
      </main>
    </div>
  );
};

export default SearchPage;
